import{_ as a,c as t,o as r,a1 as i}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"FAQ: Solución de problemas | Antigravity-Manager","description":"Domina los métodos de solución de problemas comunes de Antigravity Tools. Incluye escenarios como desactivación de cuentas, fallas de autenticación y errores de limitación.","frontmatter":{"title":"FAQ: Solución de problemas | Antigravity-Manager","sidebarTitle":"¿Qué hacer cuando hay errores","subtitle":"FAQ: Solución de problemas","description":"Domina los métodos de solución de problemas comunes de Antigravity Tools. Incluye escenarios como desactivación de cuentas, fallas de autenticación y errores de limitación.","order":4},"headers":[],"relativePath":"es/lbjlaq/Antigravity-Manager/faq/index.md","filePath":"es/lbjlaq/Antigravity-Manager/faq/index.md"}'),n={name:"es/lbjlaq/Antigravity-Manager/faq/index.md"};function o(s,e,d,c,l,u){return r(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="preguntas-frecuentes" tabindex="-1">Preguntas frecuentes <a class="header-anchor" href="#preguntas-frecuentes" aria-label="Permalink to &quot;Preguntas frecuentes&quot;">​</a></h1><p>Este capítulo recopila los códigos de error y escenarios de excepción más comunes al usar Antigravity Tools, ayudándote a localizar rápidamente la causa raíz del problema y encontrar soluciones.</p><h2 id="contenido-de-este-capitulo" tabindex="-1">Contenido de este capítulo <a class="header-anchor" href="#contenido-de-este-capitulo" aria-label="Permalink to &quot;Contenido de este capítulo&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Tipo de problema</th><th>Página</th><th>Descripción</th></tr></thead><tbody><tr><td>Cuenta desactivada</td><td><a href="./invalid-grant/">invalid_grant y desactivación automática de cuentas</a></td><td>¿La cuenta de repente no está disponible? Entiende las causas de la invalidación del token OAuth y el proceso de recuperación</td></tr><tr><td>Falla de autenticación</td><td><a href="./auth-401/">401/falla de autenticación</a></td><td>¿Solicitud rechazada? Verifica la configuración de auth_mode y el formato de Header</td></tr><tr><td>Error de limitación</td><td><a href="./429-rotation/">429/error de capacidad</a></td><td>¿429 frecuente? Distingue entre cuota insuficiente y limitación upstream, usa estrategias de rotación para reducir el impacto</td></tr><tr><td>Error de ruta</td><td><a href="./404-base-url/">404/ruta incompatible</a></td><td>¿API 404? Resuelve el problema de concatenación de Base URL y prefijo /v1</td></tr><tr><td>Excepción de streaming</td><td><a href="./streaming-0token/">interrupción de streaming/0 Token/firma inválida</a></td><td>¿Respuesta interrumpida o vacía? Entiende el mecanismo de autorecuperación del proxy y la ruta de investigación</td></tr></tbody></table><h2 id="ruta-de-aprendizaje-recomendada" tabindex="-1">Ruta de aprendizaje recomendada <a class="header-anchor" href="#ruta-de-aprendizaje-recomendada" aria-label="Permalink to &quot;Ruta de aprendizaje recomendada&quot;">​</a></h2><p><strong>Investigación por código de error</strong>: Cuando encuentres un error específico, ve directamente a la página correspondiente.</p><p><strong>Aprendizaje sistemático</strong>: Si deseas comprender completamente los posibles problemas, se recomienda leer en el siguiente orden:</p><ol><li><strong><a href="./404-base-url/">404/ruta incompatible</a></strong> — El problema más común de integración, generalmente el primer obstáculo</li><li><strong><a href="./auth-401/">401/falla de autenticación</a></strong> — La ruta es correcta pero la solicitud es rechazada, verifica la configuración de autenticación</li><li><strong><a href="./invalid-grant/">invalid_grant y desactivación automática de cuentas</a></strong> — Problemas a nivel de cuenta</li><li><strong><a href="./429-rotation/">429/error de capacidad</a></strong> — La solicitud tiene éxito pero está limitada</li><li><strong><a href="./streaming-0token/">interrupción de streaming/0 Token/firma inválida</a></strong> — Problemas avanzados, involucran respuestas de streaming y mecanismos de firma</li></ol><h2 id="requisitos-previos" tabindex="-1">Requisitos previos <a class="header-anchor" href="#requisitos-previos" aria-label="Permalink to &quot;Requisitos previos&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Recomendación</p><ul><li><a href="./../start/proxy-and-first-client/">Iniciar proxy local e integrar el primer cliente</a> — Asegúrate de que el entorno básico funcione</li><li><a href="./../start/add-account/">Agregar cuentas</a> — Conoce la forma correcta de agregar cuentas</li></ul></div><h2 id="siguientes-pasos" tabindex="-1">Siguientes pasos <a class="header-anchor" href="#siguientes-pasos" aria-label="Permalink to &quot;Siguientes pasos&quot;">​</a></h2><p>Después de resolver los problemas, puedes continuar con un aprendizaje profundo:</p><ul><li><strong><a href="./../advanced/scheduling/">Programación de alta disponibilidad</a></strong> — Usa estrategias de rotación y reintento para reducir la ocurrencia de errores</li><li><strong><a href="./../advanced/monitoring/">Proxy Monitor</a></strong> — Usa el sistema de registros para rastrear detalles de solicitudes</li><li><strong><a href="./../advanced/config/">Guía completa de configuración</a></strong> — Conoce el propósito de todos los elementos de configuración</li></ul>',13)])])}const g=a(n,[["render",o]]);export{m as __pageData,g as default};
